import sys

def main():
    n, m, q = map(int, sys.stdin.readline().split())
    grid = [[1] * (m + 2) for _ in range(n + 2)]
    for i in range(1, n+1):
        for j in range(1, m+1):
            grid[i][j] = 1
    res = 0
    dp1 = [[0] * (m + 2) for _ in range(n + 2)]
    dp2 = [[0] * (m + 2) for _ in range(n + 2)]
    for i in range(1, n+1):
        for j in range(1, m+1):
            dp1[i][j] = dp1[i][j-1] + 1 if grid[i][j] else 0
            dp2[i][j] = dp2[i-1][j] + 1 if grid[i][j] else 0
            res += dp1[i][j] + dp2[i][j] - 1
    for _ in range(q):
        x, y = map(int, sys.stdin.readline().split())
        if grid[x][y]:
            res -= dp1[x][y] + dp2[x][y] - 1
            grid[x][y] = 0
